def set_bit(num: int, i: int) -> int:
    """
    Belirli bir sayının i'nci bitini 1 (set) yapar.
    """
    return num | (1 << i)

def clear_bit(num: int, i: int) -> int:
    """
    Belirli bir sayının i'nci bitini 0 (clear) yapar.
    """
    return num & (~(1 << i))

def toggle_bit(num: int, i: int) -> int:
    """
    Belirli bir sayının i'nci bitini tersine çevirir (0 ise 1, 1 ise 0 yapar).
    """
    return num ^ (1 << i)
